import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { 
  FaSearch, FaUpload, FaInfoCircle, FaHome, 
  FaGraduationCap, FaSignInAlt, FaUserPlus, FaBars, FaTimes,
  FaBook, FaLaptop, FaChartBar, FaBriefcase, FaCode,
  FaUserCircle, FaSignOutAlt, FaAngleDown
} from 'react-icons/fa';

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [activeDropdown, setActiveDropdown] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [showSearchResults, setShowSearchResults] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [user, setUser] = useState(null);
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(false);
  const [logoPosition, setLogoPosition] = useState(0);
  
  const navigate = useNavigate();
  const location = useLocation();

  // Scroll effect
  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Logo animation - Study Portal apni jagah ghumta rahe
  useEffect(() => {
    const interval = setInterval(() => {
      setLogoPosition(prev => (prev + 1) % 4);
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  // Close menu on route change
  useEffect(() => {
    setIsMenuOpen(false);
    setActiveDropdown(null);
    setShowSearchResults(false);
  }, [location]);

  // Check login status
  useEffect(() => {
    const token = localStorage.getItem('study_portal_token');
    const userData = localStorage.getItem('study_portal_user');
    if (token && userData) {
      setIsLoggedIn(true);
      setUser(JSON.parse(userData));
    }
  }, []);

  // Fetch courses for dropdown
  useEffect(() => {
    fetchCourses();
  }, []);

  // Debounced search
  useEffect(() => {
    const timer = setTimeout(() => {
      if (searchQuery.length > 2) {
        performSearch();
      } else {
        setSearchResults([]);
      }
    }, 300);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const fetchCourses = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/courses');
      const data = await response.json();
      if (data.success) {
        setCourses(data.courses.slice(0, 6));
      } else {
        // Fallback courses
        setCourses([
          { id: 1, name: 'B.Tech', icon: '💻', code: 'BTECH', students: 1234 },
          { id: 2, name: 'BCA', icon: '📱', code: 'BCA', students: 2345 },
          { id: 3, name: 'BBA', icon: '📊', code: 'BBA', students: 3456 },
          { id: 4, name: 'MBA', icon: '🎓', code: 'MBA', students: 4567 },
          { id: 5, name: 'MCA', icon: '💼', code: 'MCA', students: 5678 },
        ]);
      }
    } catch (error) {
      setCourses([
        { id: 1, name: 'B.Tech', icon: '💻', code: 'BTECH', students: 1234 },
        { id: 2, name: 'BCA', icon: '📱', code: 'BCA', students: 2345 },
        { id: 3, name: 'BBA', icon: '📊', code: 'BBA', students: 3456 },
        { id: 4, name: 'MBA', icon: '🎓', code: 'MBA', students: 4567 },
        { id: 5, name: 'MCA', icon: '💼', code: 'MCA', students: 5678 },
      ]);
    }
  };

  const performSearch = async () => {
    setLoading(true);
    try {
      const response = await fetch(`http://localhost:5000/api/search?q=${searchQuery}`);
      const data = await response.json();
      if (data.success) {
        setSearchResults(data.results.slice(0, 5));
      } else {
        setSearchResults([
          { id: 1, type: 'course', title: 'BCA', description: 'Bachelor of Computer Applications' },
          { id: 2, type: 'notes', title: 'C Programming Notes', description: 'Complete C programming notes' },
          { id: 3, type: 'pyq', title: 'B.Tech PYQs 2024', description: 'Previous year question papers' },
        ]);
      }
    } catch (error) {
      setSearchResults([
        { id: 1, type: 'course', title: 'BCA', description: 'Bachelor of Computer Applications' },
        { id: 2, type: 'notes', title: 'C Programming Notes', description: 'Complete C programming notes' },
        { id: 3, type: 'pyq', title: 'B.Tech PYQs 2024', description: 'Previous year question papers' },
      ]);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
      setShowSearchResults(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('study_portal_token');
    localStorage.removeItem('study_portal_user');
    setIsLoggedIn(false);
    setUser(null);
    navigate('/');
  };

  // Nav items
  const navItems = [
    { name: 'Home', icon: <FaHome />, path: '/' },
    { name: 'Courses', icon: <FaGraduationCap />, path: '/courses', hasDropdown: true },
    { name: 'Upload', icon: <FaUpload />, path: '/upload' },
    { name: 'About', icon: <FaInfoCircle />, path: '/about' },
  ];

  // Logo animation positions
  const logoAnimations = [
    { transform: 'translateY(0)' },
    { transform: 'translateY(-3px)' },
    { transform: 'translateY(0)' },
    { transform: 'translateY(3px)' },
  ];

  const styles = {
    navbar: {
      background: isScrolled 
        ? 'linear-gradient(135deg, #2563eb 0%, #3b82f6 50%, #60a5fa 100%)' 
        : 'linear-gradient(135deg, #3b82f6 0%, #2563eb 50%, #1d4ed8 100%)',
      padding: '0.8rem 2rem',
      position: 'sticky',
      top: 0,
      zIndex: 1000,
      transition: 'all 0.3s ease',
      boxShadow: isScrolled 
        ? '0 10px 30px rgba(37, 99, 235, 0.3)' 
        : '0 4px 15px rgba(0, 0, 0, 0.2)',
    },
    container: {
      maxWidth: '1400px',
      margin: '0 auto',
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      gap: '1rem'
    },
    logo: {
      color: 'white',
      fontSize: '1.6rem',
      fontWeight: '800',
      textDecoration: 'none',
      display: 'flex',
      alignItems: 'center',
      gap: '0.8rem',
      background: 'rgba(255, 255, 255, 0.1)',
      padding: '0.5rem 1.2rem',
      borderRadius: '50px',
      transition: 'all 0.3s',
      border: '2px solid rgba(255, 255, 255, 0.2)',
      animation: 'float 3s ease-in-out infinite',
      ...logoAnimations[logoPosition]
    },
    logoIcon: {
      fontSize: '2rem',
      background: 'linear-gradient(135deg, #60a5fa, #93c5fd)',
      padding: '0.5rem',
      borderRadius: '50%',
    },
    searchContainer: {
      position: 'relative',
      flex: 1,
      maxWidth: '350px',
      marginLeft: 'auto',
      marginRight: '1rem'
    },
    searchForm: {
      display: 'flex',
      alignItems: 'center',
      background: 'rgba(255, 255, 255, 0.15)',
      borderRadius: '30px',
      border: '2px solid rgba(255, 255, 255, 0.2)',
      transition: 'all 0.3s',
      '&:focus-within': {
        background: 'white',
        borderColor: '#60a5fa',
        boxShadow: '0 8px 20px rgba(96, 165, 250, 0.3)'
      }
    },
    searchInput: {
      flex: 1,
      padding: '0.7rem 1.2rem',
      background: 'transparent',
      border: 'none',
      color: 'white',
      fontSize: '0.9rem',
      outline: 'none',
      '&::placeholder': {
        color: 'rgba(255, 255, 255, 0.8)'
      },
      '&:focus': {
        color: '#333'
      }
    },
    searchButton: {
      background: 'rgba(255, 255, 255, 0.2)',
      border: 'none',
      borderRadius: '0 30px 30px 0',
      padding: '0.7rem 1.2rem',
      color: 'white',
      cursor: 'pointer',
      display: 'flex',
      alignItems: 'center',
      gap: '0.3rem',
      fontWeight: '600',
      fontSize: '0.9rem',
      transition: 'all 0.3s',
      '&:hover': {
        background: 'rgba(255, 255, 255, 0.3)',
      }
    },
    searchResults: {
      position: 'absolute',
      top: '100%',
      left: 0,
      right: 0,
      background: 'white',
      borderRadius: '12px',
      boxShadow: '0 10px 30px rgba(0,0,0,0.15)',
      marginTop: '0.5rem',
      maxHeight: '350px',
      overflowY: 'auto',
      zIndex: 1000,
      animation: 'slideDown 0.3s ease'
    },
    navLinks: {
      display: 'flex',
      gap: '0.2rem',
      alignItems: 'center'
    },
    link: {
      color: 'white',
      textDecoration: 'none',
      padding: '0.6rem 1rem',
      borderRadius: '20px',
      transition: 'all 0.3s',
      display: 'flex',
      alignItems: 'center',
      gap: '0.4rem',
      fontSize: '0.95rem',
      fontWeight: '500',
      cursor: 'pointer',
      background: 'transparent',
      border: 'none',
    },
    activeLink: {
      background: 'rgba(255, 255, 255, 0.15)',
    },
    dropdownWrapper: {
      position: 'relative'
    },
    dropdownMenu: {
      position: 'absolute',
      top: '100%',
      left: 0,
      minWidth: '400px',
      background: 'white',
      borderRadius: '12px',
      boxShadow: '0 10px 30px rgba(0,0,0,0.15)',
      padding: '1rem',
      marginTop: '0.5rem',
      zIndex: 1000,
      animation: 'slideDown 0.3s ease'
    },
    dropdownGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(2, 1fr)',
      gap: '0.5rem'
    },
    dropdownItem: {
      display: 'flex',
      alignItems: 'center',
      gap: '0.8rem',
      padding: '0.8rem',
      borderRadius: '8px',
      cursor: 'pointer',
      transition: 'all 0.2s',
      background: '#f8fafc',
      border: '1px solid #e2e8f0',
      '&:hover': {
        background: '#e0f2fe',
        borderColor: '#3b82f6'
      }
    },
    courseIcon: {
      fontSize: '1.5rem',
      width: '40px',
      height: '40px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: '#3b82f6',
      color: 'white',
      borderRadius: '8px',
    },
    authButtons: {
      display: 'flex',
      gap: '0.5rem',
      marginLeft: '0.5rem'
    },
    loginBtn: {
      background: 'transparent',
      border: '2px solid white',
      color: 'white',
      padding: '0.6rem 1.2rem',
      borderRadius: '25px',
      cursor: 'pointer',
      fontWeight: '500',
      fontSize: '0.9rem',
      display: 'flex',
      alignItems: 'center',
      gap: '0.4rem',
      transition: 'all 0.3s',
      '&:hover': {
        background: 'white',
        color: '#3b82f6'
      }
    },
    registerBtn: {
      background: 'white',
      border: '2px solid white',
      color: '#3b82f6',
      padding: '0.6rem 1.2rem',
      borderRadius: '25px',
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '0.9rem',
      display: 'flex',
      alignItems: 'center',
      gap: '0.4rem',
      transition: 'all 0.3s',
      '&:hover': {
        background: 'transparent',
        color: 'white'
      }
    },
    userMenu: {
      display: 'flex',
      alignItems: 'center',
      gap: '0.8rem',
      marginLeft: '0.5rem'
    },
    userAvatar: {
      width: '40px',
      height: '40px',
      borderRadius: '50%',
      background: 'linear-gradient(135deg, #60a5fa, #93c5fd)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      color: '#1e40af',
      fontSize: '1.2rem',
      fontWeight: 'bold',
      cursor: 'pointer',
      border: '2px solid white',
    },
    mobileBtn: {
      display: 'none',
      background: 'rgba(255, 255, 255, 0.2)',
      border: '2px solid white',
      color: 'white',
      fontSize: '1.2rem',
      cursor: 'pointer',
      padding: '0.5rem',
      borderRadius: '8px',
    }
  };

  return (
    <nav style={styles.navbar}>
      <div style={styles.container}>
        {/* Logo - Ghumta rahega */}
        <Link to="/" style={styles.logo}>
          <span style={styles.logoIcon}>📚</span>
          <span>Study Portal</span>
        </Link>

        {/* Desktop Menu */}
        <div style={{ display: 'flex', alignItems: 'center', flex: 1, justifyContent: 'flex-end' }}>
          <div style={styles.navLinks}>
            {navItems.map(item => (
              item.hasDropdown ? (
                <div key={item.name} style={styles.dropdownWrapper}>
                  <button
                    style={{
                      ...styles.link,
                      ...(activeDropdown === 'courses' ? styles.activeLink : {})
                    }}
                    onClick={() => setActiveDropdown(activeDropdown === 'courses' ? null : 'courses')}
                    onMouseEnter={() => setActiveDropdown('courses')}
                  >
                    {item.icon} {item.name} <FaAngleDown style={{ fontSize: '0.8rem' }} />
                  </button>

                  {activeDropdown === 'courses' && (
                    <div 
                      style={styles.dropdownMenu}
                      onMouseLeave={() => setActiveDropdown(null)}
                    >
                      <div style={styles.dropdownGrid}>
                        {courses.map(course => (
                          <div
                            key={course.id}
                            style={styles.dropdownItem}
                            onClick={() => {
                              navigate(`/course/${course.id}`);
                              setActiveDropdown(null);
                            }}
                          >
                            <div style={styles.courseIcon}>
                              {course.icon}
                            </div>
                            <div>
                              <div style={{ fontWeight: '600', color: '#1e293b' }}>{course.name}</div>
                              <div style={{ fontSize: '0.7rem', color: '#64748b' }}>
                                {course.students} students
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              ) : (
                <Link
                  key={item.name}
                  to={item.path}
                  style={{
                    ...styles.link,
                    ...(location.pathname === item.path ? styles.activeLink : {})
                  }}
                >
                  {item.icon} {item.name}
                </Link>
              )
            ))}
          </div>

          {/* Search Bar */}
          <div style={styles.searchContainer}>
            <form onSubmit={handleSearch} style={styles.searchForm}>
              <input
                type="text"
                placeholder="Search courses, notes, PYQs..."
                value={searchQuery}
                onChange={(e) => {
                  setSearchQuery(e.target.value);
                  setShowSearchResults(true);
                }}
                onFocus={() => setShowSearchResults(true)}
                style={styles.searchInput}
              />
              <button type="submit" style={styles.searchButton}>
                <FaSearch /> Search
              </button>
            </form>

            {/* Search Results */}
            {showSearchResults && searchQuery.length > 2 && (
              <div style={styles.searchResults}>
                {loading ? (
                  <div style={{ padding: '1rem', textAlign: 'center' }}>Searching...</div>
                ) : searchResults.length > 0 ? (
                  searchResults.map(result => (
                    <div
                      key={result.id}
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: '1rem',
                        padding: '0.8rem 1rem',
                        borderBottom: '1px solid #e2e8f0',
                        cursor: 'pointer',
                        '&:hover': { background: '#f1f5f9' }
                      }}
                      onClick={() => {
                        navigate(`/${result.type}/${result.id}`);
                        setShowSearchResults(false);
                        setSearchQuery('');
                      }}
                    >
                      <span style={{ fontSize: '1.2rem' }}>
                        {result.type === 'course' ? '📚' : 
                         result.type === 'notes' ? '📝' : '📄'}
                      </span>
                      <div>
                        <div style={{ fontWeight: '600' }}>{result.title}</div>
                        <div style={{ fontSize: '0.8rem', color: '#64748b' }}>{result.description}</div>
                      </div>
                    </div>
                  ))
                ) : (
                  <div style={{ padding: '1rem', textAlign: 'center', color: '#64748b' }}>
                    No results found
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Auth Buttons - Last mein */}
          {isLoggedIn ? (
            <div style={styles.userMenu}>
              <div 
                style={styles.userAvatar}
                onClick={() => navigate('/profile')}
              >
                {user?.name?.charAt(0) || <FaUserCircle />}
              </div>
              <button 
                onClick={handleLogout}
                style={styles.loginBtn}
              >
                <FaSignOutAlt /> Logout
              </button>
            </div>
          ) : (
            <div style={styles.authButtons}>
              <button style={styles.loginBtn} onClick={() => navigate('/login')}>
                <FaSignInAlt /> Login
              </button>
              <button style={styles.registerBtn} onClick={() => navigate('/register')}>
                <FaUserPlus /> Register
              </button>
            </div>
          )}
        </div>

        {/* Mobile Menu Button */}
        <button style={styles.mobileBtn} onClick={() => setIsMenuOpen(!isMenuOpen)}>
          {isMenuOpen ? <FaTimes /> : <FaBars />}
        </button>
      </div>

      <style>
        {`
          @keyframes slideDown {
            from {
              opacity: 0;
              transform: translateY(-10px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }
          
          @keyframes float {
            0% { transform: translateY(0px); }
            50% { transform: translateY(-5px); }
            100% { transform: translateY(0px); }
          }
          
          button, a {
            transition: all 0.3s ease;
          }
          
          button:hover, a:hover {
            transform: translateY(-2px);
          }
        `}
      </style>
    </nav>
  );
};

export default Navbar;
